/**
 * Helper function to check if a number is prime.
 * Time complexity: O(sqrt(num))
 * @param {number} num 
 * @returns {boolean}
 */
function isPrime(num) {
    if (num <= 1) return false;
    if (num <= 3) return true;
    if (num % 2 === 0 || num % 3 === 0) return false;

    let i = 5;
    while (i * i <= num) {
        if (num % i === 0 || num % (i + 2) === 0) return false;
        i += 6;
    }
    return true;
}

/**
 * Helper function to reverse the digits of an integer.
 * @param {number} n 
 * @returns {number}
 */
function reverseN(n) {
    const s = String(n);
    const reversedS = s.split('').reverse().join('');
    // parseInt handles leading zeros correctly (e.g., "01" becomes 1)
    return parseInt(reversedS, 10);
}

/**
 * Calculates the sum of all prime numbers between min(n, r) and max(n, r),
 * where r is the reverse of n.
 * @param {number} n 
 * @returns {number}
 */
function solve(n) {
    // 1. Calculate r (reversed n)
    const r = reverseN(n);

    // 2. Determine the range
    const start = Math.min(n, r);
    const end = Math.max(n, r);

    // 3. Sum primes in the range
    let sum = 0;
    for (let i = start; i <= end; i++) {
        if (isPrime(i)) {
            sum += i;
        }
    }

    return sum;
}

